// Concatenate any text blocks Claude returned and parse the fact_pack JSON.
const blocks = ($json.content || []).filter(b => b.type === 'text').map(b => b.text).join('\n');
let pack = { facts: [], key_numbers: [], caveats: [] };
try { pack = JSON.parse(blocks); } catch (e) {
  const m = blocks.match(/\{[\s\S]*\}/); if (m) pack = JSON.parse(m[0]);
}
const job = $('Load + lock job').first().json;
return [{ json: { ...job, fact_pack: pack, sources: (pack.facts||[]).map(f => f.source_url).filter(Boolean) } }];

