  messages: [{ role: 'user', content: `Given SCRIPT and SOURCES, for each factual claim output {claim, verdict: supported|unsupported|needs_review, note}. A claim is supported only if a provided source with a date backs it. Then COMPLIANCE_CHECK for any buy/sell view, target price, return prediction, forex promotion, or crypto claim missing the ASCI disclaimer. Return JSON only: {claims:[...], compliance:"PASS|FAIL", reasons:[]}.

SCRIPT:
${$json.script}

SOURCES:
${JSON.stringify($json.fact_pack)}` }]
}) }}

parameters.jsCode:
const text = $json.content?.[0]?.text ?? '{}';
let fc = { compliance: 'FAIL', claims: [], reasons: ['unparseable'] };
try { fc = JSON.parse(text); } catch (e) { const m = text.match(/\{[\s\S]*\}/); if (m) fc = JSON.parse(m[0]); }
const bad = (fc.claims||[]).some(c => c.verdict === 'unsupported' || c.verdict === 'needs_review');
const pass = fc.compliance === 'PASS' && !bad;
const prev = $('Parse script').first().json;
return [{ json: { ...prev, factcheck: pass ? 'PASS' : 'FLAG', flags: pass ? [] : (fc.reasons||[]).concat((fc.claims||[]).filter(c=>c.verdict!=='supported').map(c=>c.claim)), showCryptoDisclaimer: /crypto|bitcoin|nft|token/i.test(prev.script) } }];

